"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const notes=[['Source audit','12 references reconciled'],['Customer call','Three teams named the same need'],['Prototype test','Task time fell by 18%']];
export default function EvidenceThreadCard(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <section aria-labelledby="thread-title" className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">evidence thread</p><h2 id="thread-title" className="mt-1 text-xl font-black text-[#111]">Why this holds</h2><div className="relative mt-4 border-l border-[#ececee] pl-5"><motion.i aria-hidden animate={{y:active*58}} transition={reduced?{duration:.12}:{type:'spring',stiffness:320,damping:26}} className="absolute -left-[5px] top-3 block h-2.5 w-2.5 rounded-full bg-[#f59e0b]"/>{notes.map((note,index)=><motion.button key={note[0]} type="button" aria-pressed={active===index} onClick={()=>setActive(index)} whileHover={reduced?undefined:{y:-2}} whileTap={reduced?undefined:{y:1}} className="mb-2 min-h-11 w-full rounded-xl border border-[#ececee] px-3 py-2 text-left outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]"><span className="block text-sm font-bold text-[#111]">{index+1}. {note[0]}</span>{active===index&&<motion.span initial={{opacity:0}} animate={{opacity:1}} className="mt-1 block text-xs text-[#4a4a4f]">{note[1]}</motion.span>}</motion.button>)}</div><p aria-live="polite" className="text-xs text-[#4a4a4f]">Selected: {notes[active][0]}.</p></section>}
